#pragma once

#include <tesla.hpp>

class AlphaSymbol {
  private:
    s32 m_width;
    s32 m_height;
    const u8 *m_data;

  public:
    constexpr AlphaSymbol(size_t width, size_t height, const u8 *data)
        : m_width(width), m_height(height), m_data(data) {}

    void draw(s32 x, s32 y, tsl::gfx::Renderer *renderer, tsl::Color color) const {
        const u8 *ptr = this->m_data;
        const s32 x_offset = x - (m_width / 2);
        const s32 y_offset = y - (m_height / 2);
        const u8 opacity_limit = static_cast<u8>(0xF * tsl::gfx::Renderer::s_opacity);
        for (s32 y1 = 0; y1 < m_height; y1++) {
            for (s32 x1 = 0; x1 < m_width; x1++) {
                const u8 a = static_cast<u8>(ptr[0] >> 4);
                if (a > 0) {
                    color.a = a < opacity_limit ? a : opacity_limit;
                    renderer->setPixelBlendSrc(x_offset + x1, y_offset + y1, color);
                }
                ptr++;
            }
        }
    }
    
    /* Bilinear-filtered scaled draw — replaces the old nearest-neighbour version. */
    void draw(s32 x, s32 y, tsl::gfx::Renderer *renderer, tsl::Color color, float scale) const {
        const s32 sw = static_cast<s32>(m_width  * scale);
        const s32 sh = static_cast<s32>(m_height * scale);
        const s32 x_offset = x - (sw / 2);
        const s32 y_offset = y - (sh / 2);
        const u8 opacity_limit = static_cast<u8>(0xF * tsl::gfx::Renderer::s_opacity);
    
        for (s32 y1 = 0; y1 < sh; y1++) {
            // Map destination pixel center back to source space
            const float sy = (y1 + 0.5f) * static_cast<float>(m_height) / static_cast<float>(sh) - 0.5f;
            const s32   y0 = static_cast<s32>(sy);
            const float fy = sy - static_cast<float>(y0);
            const s32   ya = std::max(0, std::min(m_height - 1, y0));
            const s32   yb = std::max(0, std::min(m_height - 1, y0 + 1));
    
            for (s32 x1 = 0; x1 < sw; x1++) {
                const float sx = (x1 + 0.5f) * static_cast<float>(m_width) / static_cast<float>(sw) - 0.5f;
                const s32   x0 = static_cast<s32>(sx);
                const float fx = sx - static_cast<float>(x0);
                const s32   xa = std::max(0, std::min(m_width - 1, x0));
                const s32   xb = std::max(0, std::min(m_width - 1, x0 + 1));
    
                // Bilinear interpolation on raw byte values, then shift >>4 at the end
                const float v = m_data[ya * m_width + xa] * (1.f - fx) * (1.f - fy)
                              + m_data[ya * m_width + xb] * fx          * (1.f - fy)
                              + m_data[yb * m_width + xa] * (1.f - fx) * fy
                              + m_data[yb * m_width + xb] * fx          * fy;
    
                const u8 a = static_cast<u8>(v) >> 4;
                if (a > 0) {
                    color.a = a < opacity_limit ? a : opacity_limit;
                    renderer->setPixelBlendSrc(x_offset + x1, y_offset + y1, color);
                }
            }
        }
    }
};

